class DepartmentService{async _api(e,t={}){return window.Utils?await window.Utils.callApi(e,t):{status:"error",message:"Lỗi hệ thống"}}async getAll(){return await this._api("fetch_deparments")}async create(e){return await this._api("create_department",e)}async update(e){return await this._api("update_department",e)}async delete(e){return await this._api("delete_department",{id:e})}}export default new DepartmentService;